import { Pool } from 'pg'

export function validateDatabaseUrl(rawInput: string | undefined): string {
  const raw = (rawInput ?? '').trim()
  if (!raw) throw new Error('DATABASE_URL is required')

  let parsed: URL
  try {
    parsed = new URL(raw)
  } catch {
    throw new Error('DATABASE_URL is invalid. Expected format: postgres://host:5432/dbname')
  }

  if (parsed.protocol !== 'postgres:' && parsed.protocol !== 'postgresql:') {
    throw new Error(`DATABASE_URL protocol must be postgres or postgresql, got ${parsed.protocol}`)
  }

  if (!parsed.hostname) {
    throw new Error('DATABASE_URL must include a hostname')
  }

  if (!parsed.pathname || parsed.pathname === '/') {
    throw new Error('DATABASE_URL must include a database name in path')
  }

  return raw
}

export function getDatabaseUrl(): string {
  return validateDatabaseUrl(process.env.DATABASE_URL)
}

export function createPool(): Pool {
  return new Pool({ connectionString: getDatabaseUrl() })
}

